const fs = require('fs'); const path = require('path');
const root = __dirname;
const files = {"src/app/globals.css": "@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');\n\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n:root {\n  /* Core palette */\n  --bg:           #F8F7F5;\n  --surface:      #FFFFFF;\n  --surface-2:    #F2F1EF;\n  --border:       #E4E2DD;\n  --border-strong:#C8C5BE;\n\n  /* Text */\n  --text:         #0F0F0E;\n  --text-2:       #4A4845;\n  --text-3:       #8A8680;\n  --text-4:       #B5B2AC;\n\n  /* Accent — forest green */\n  --green:        #1A5C3A;\n  --green-mid:    #2D7A51;\n  --green-light:  #E8F2EC;\n  --green-border: #B8D9C4;\n\n  /* States */\n  --amber:        #92600A;\n  --amber-light:  #FEF3E2;\n  --amber-border: #F0D090;\n  --red:          #C0392B;\n  --red-light:    #FDECEA;\n  --red-border:   #F0B8B2;\n  --blue:         #1B4F8A;\n  --blue-light:   #EBF2FB;\n  --blue-border:  #B8CFF0;\n\n  /* Radii */\n  --r-sm: 4px;\n  --r:    8px;\n  --r-lg: 12px;\n\n  /* Shadows */\n  --shadow-sm: 0 1px 3px rgba(0,0,0,.06), 0 1px 2px rgba(0,0,0,.04);\n  --shadow:    0 2px 8px rgba(0,0,0,.08), 0 1px 3px rgba(0,0,0,.05);\n  --shadow-lg: 0 8px 32px rgba(0,0,0,.10), 0 2px 8px rgba(0,0,0,.06);\n}\n\nhtml { -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }\n\nbody {\n  font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;\n  font-size: 14px;\n  line-height: 1.5;\n  color: var(--text);\n  background: var(--bg);\n  min-height: 100vh;\n}\n\n/* ── Layout ── */\n.page { min-height: 100vh; display: flex; flex-direction: column; }\n.container { width: 100%; max-width: 640px; margin: 0 auto; padding: 0 20px; }\n.container-wide { width: 100%; max-width: 1140px; margin: 0 auto; padding: 0 24px; }\n\n/* ── Header ── */\n.header {\n  background: var(--surface);\n  border-bottom: 1px solid var(--border);\n  padding: 0;\n  position: sticky; top: 0; z-index: 50;\n  box-shadow: var(--shadow-sm);\n}\n.header-inner {\n  display: flex; align-items: center;\n  justify-content: space-between;\n  gap: 16px;\n  height: 56px;\n}\n.header-title { font-size: 15px; font-weight: 600; letter-spacing: -.01em; color: var(--text); }\n.header-sub   { font-size: 11px; color: var(--text-3); margin-top: 1px; letter-spacing: .01em; }\n\n/* ── Cards ── */\n.card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: var(--r-lg);\n  padding: 20px;\n  box-shadow: var(--shadow-sm);\n}\n.card + .card { margin-top: 12px; }\n\n.card-title {\n  font-size: 10px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: .08em;\n  color: var(--text-3);\n  margin-bottom: 14px;\n}\n\n/* ── Buttons ── */\n.btn {\n  display: inline-flex; align-items: center; justify-content: center; gap: 6px;\n  padding: 0 14px; height: 34px;\n  border-radius: var(--r-sm);\n  border: 1px solid var(--border-strong);\n  background: var(--surface);\n  color: var(--text-2);\n  font-size: 13px; font-weight: 500;\n  font-family: inherit;\n  cursor: pointer;\n  transition: all .12s ease;\n  white-space: nowrap;\n  letter-spacing: -.01em;\n}\n.btn:hover { background: var(--surface-2); border-color: var(--border-strong); color: var(--text); }\n.btn:active { transform: scale(.98); }\n.btn:disabled { opacity: .4; cursor: not-allowed; transform: none; }\n\n.btn-sm  { height: 28px; padding: 0 10px; font-size: 12px; }\n.btn-lg  { height: 44px; padding: 0 24px; font-size: 14px; font-weight: 600; }\n.btn-full { width: 100%; }\n\n.btn-primary {\n  background: var(--green);\n  color: #fff;\n  border-color: var(--green);\n  font-weight: 600;\n}\n.btn-primary:hover { background: var(--green-mid); border-color: var(--green-mid); color: #fff; }\n\n.btn-success {\n  background: var(--green);\n  color: #fff;\n  border-color: var(--green);\n}\n.btn-success:hover { background: var(--green-mid); border-color: var(--green-mid); color: #fff; }\n\n.btn-danger {\n  background: var(--red);\n  color: #fff;\n  border-color: var(--red);\n}\n.btn-danger:hover { background: #a93226; color: #fff; }\n\n.btn-ghost {\n  background: transparent;\n  border-color: transparent;\n  color: var(--text-3);\n}\n.btn-ghost:hover { background: var(--surface-2); border-color: var(--border); color: var(--text-2); }\n\n/* ── Inputs ── */\n.field { margin-bottom: 16px; }\n.field:last-child { margin-bottom: 0; }\n\n.label {\n  display: block;\n  font-size: 11px;\n  font-weight: 600;\n  text-transform: uppercase;\n  letter-spacing: .06em;\n  color: var(--text-3);\n  margin-bottom: 6px;\n}\n.label .req { color: var(--red); margin-left: 2px; }\n\ninput[type=text],\ninput[type=number],\ninput[type=password],\ninput[type=date],\nselect,\ntextarea {\n  width: 100%;\n  height: 38px;\n  padding: 0 12px;\n  border: 1px solid var(--border-strong);\n  border-radius: var(--r-sm);\n  background: var(--surface);\n  color: var(--text);\n  font-size: 14px;\n  font-family: 'Inter', sans-serif;\n  outline: none;\n  transition: border-color .12s, box-shadow .12s;\n  appearance: none;\n  -webkit-appearance: none;\n}\ninput:focus, select:focus, textarea:focus {\n  border-color: var(--green);\n  box-shadow: 0 0 0 3px rgba(26,92,58,.10);\n}\ninput[type=number] { -moz-appearance: textfield; }\ninput[type=number]::-webkit-inner-spin-button { opacity: .5; }\n\n.field-error {\n  font-size: 11px;\n  color: var(--red);\n  margin-top: 5px;\n  font-weight: 500;\n}\n\n.input-row { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }\n\n/* ── Chips ── */\n.chip-group { display: flex; flex-wrap: wrap; gap: 6px; }\n\n.chip {\n  padding: 5px 12px;\n  border-radius: 100px;\n  font-size: 12px;\n  font-weight: 500;\n  cursor: pointer;\n  border: 1px solid var(--border-strong);\n  background: var(--surface);\n  color: var(--text-2);\n  transition: all .1s;\n  user-select: none;\n  letter-spacing: -.01em;\n}\n.chip:hover { border-color: var(--green); color: var(--green); background: var(--green-light); }\n.chip.active { background: var(--green); color: #fff; border-color: var(--green); }\n\n/* ── Tags (selected items) ── */\n.tag {\n  display: inline-flex; align-items: center; gap: 4px;\n  padding: 4px 8px 4px 12px;\n  border-radius: 100px;\n  font-size: 12px;\n  font-weight: 500;\n  background: var(--surface-2);\n  border: 1px solid var(--border);\n  color: var(--text-2);\n}\n.tag-del {\n  cursor: pointer;\n  color: var(--text-4);\n  font-size: 16px;\n  line-height: 1;\n  transition: color .1s;\n}\n.tag-del:hover { color: var(--red); }\n\n/* ── Badges ── */\n.badge {\n  display: inline-flex; align-items: center; gap: 4px;\n  padding: 3px 8px;\n  border-radius: 100px;\n  font-size: 11px;\n  font-weight: 600;\n  letter-spacing: .02em;\n}\n.badge-pending  { background: var(--amber-light);  color: var(--amber);  border: 1px solid var(--amber-border); }\n.badge-approved { background: var(--green-light);  color: var(--green);  border: 1px solid var(--green-border); }\n.badge-flagged  { background: var(--red-light);    color: var(--red);    border: 1px solid var(--red-border); }\n.badge-info     { background: var(--blue-light);   color: var(--blue);   border: 1px solid var(--blue-border); }\n\n/* ── Item cards ── */\n.item-card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: var(--r);\n  padding: 14px 16px;\n  margin-bottom: 8px;\n  transition: box-shadow .12s;\n  box-shadow: var(--shadow-sm);\n}\n.item-card:hover { box-shadow: var(--shadow); }\n\n.item-card-header { display: flex; justify-content: space-between; align-items: flex-start; gap: 12px; }\n.item-name  { font-weight: 600; font-size: 14px; letter-spacing: -.01em; }\n.item-meta  { font-size: 12px; color: var(--text-3); margin-top: 3px; }\n.item-note  { font-size: 11px; color: var(--amber); margin-top: 4px; font-weight: 500; }\n\n/* ── Stats ── */\n.stats-row { display: grid; grid-template-columns: repeat(4,1fr); gap: 10px; margin-bottom: 20px; }\n.stat-card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: var(--r);\n  padding: 14px 16px;\n  box-shadow: var(--shadow-sm);\n}\n.stat-val { font-size: 26px; font-weight: 700; letter-spacing: -.03em; line-height: 1; }\n.stat-lbl { font-size: 10px; font-weight: 600; text-transform: uppercase; letter-spacing: .07em; color: var(--text-3); margin-top: 4px; }\n\n/* ── Tabs ── */\n.tabs { display: flex; gap: 2px; margin-bottom: 20px; background: var(--surface-2); padding: 3px; border-radius: var(--r-sm); border: 1px solid var(--border); width: fit-content; }\n.tab {\n  padding: 6px 16px;\n  border-radius: 3px;\n  border: none;\n  background: transparent;\n  font-size: 12px;\n  font-weight: 500;\n  cursor: pointer;\n  font-family: inherit;\n  transition: all .12s;\n  color: var(--text-3);\n  letter-spacing: -.01em;\n}\n.tab.active { background: var(--surface); color: var(--text); box-shadow: var(--shadow-sm); font-weight: 600; }\n.tab:hover:not(.active) { color: var(--text-2); }\n\n/* ── Divider ── */\n.divider { height: 1px; background: var(--border); margin: 16px 0; }\n\n/* ── Empty state ── */\n.empty { text-align: center; padding: 48px 20px; color: var(--text-3); }\n.empty-icon { font-size: 32px; margin-bottom: 10px; opacity: .5; }\n.empty-text { font-size: 13px; font-weight: 500; }\n\n/* ── Toast ── */\n.toast-wrap {\n  position: fixed; bottom: 24px; left: 50%; transform: translateX(-50%);\n  z-index: 9999; pointer-events: none;\n}\n.toast {\n  background: var(--text);\n  color: #fff;\n  padding: 10px 20px;\n  border-radius: var(--r);\n  font-size: 13px;\n  font-weight: 500;\n  white-space: nowrap;\n  box-shadow: var(--shadow-lg);\n  animation: toastIn .18s ease;\n}\n@keyframes toastIn { from { opacity:0; transform:translateY(6px); } to { opacity:1; transform:none; } }\n\n/* ── Vendor rows ── */\n.vendor-row {\n  display: flex; justify-content: space-between; align-items: center;\n  padding: 10px 0;\n  border-bottom: 1px solid var(--border);\n  font-size: 13px;\n}\n.vendor-row:last-child { border-bottom: none; }\n\n/* ── Settings grid ── */\n.settings-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 14px; }\n@media (max-width: 480px) { .settings-grid { grid-template-columns: 1fr 1fr; } }\n\n/* ── Login page ── */\n.login-page {\n  min-height: 100vh;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  padding: 2rem;\n  background: var(--bg);\n}\n.login-card {\n  width: 100%;\n  max-width: 380px;\n}\n.login-logo {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  margin-bottom: 32px;\n}\n.login-logo img {\n  width: 72px; height: 72px;\n  border-radius: 18px;\n  box-shadow: var(--shadow-lg);\n  margin-bottom: 16px;\n}\n.login-brand {\n  font-size: 20px;\n  font-weight: 700;\n  letter-spacing: -.03em;\n  color: var(--text);\n}\n.login-sub {\n  font-size: 12px;\n  color: var(--text-3);\n  margin-top: 3px;\n  letter-spacing: .01em;\n}\n.login-form {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: var(--r-lg);\n  padding: 24px;\n  box-shadow: var(--shadow);\n}\n.login-pin-input {\n  font-size: 24px !important;\n  letter-spacing: 10px !important;\n  text-align: center !important;\n  font-family: 'JetBrains Mono', monospace !important;\n  height: 52px !important;\n}\n.login-switch {\n  margin-top: 20px;\n  text-align: center;\n  font-size: 12px;\n  color: var(--text-3);\n}\n.login-switch a {\n  color: var(--green);\n  font-weight: 600;\n  text-decoration: none;\n  cursor: pointer;\n}\n.login-switch a:hover { text-decoration: underline; }\n\n/* ── Section label ── */\n.section-label {\n  font-size: 10px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: .08em;\n  color: var(--text-3);\n  margin-bottom: 10px;\n  padding-bottom: 8px;\n  border-bottom: 1px solid var(--border);\n}\n\n/* ── Price preview box ── */\n.price-preview {\n  display: flex; gap: 20px; flex-wrap: wrap;\n  padding: 10px 14px;\n  background: var(--surface-2);\n  border-radius: var(--r-sm);\n  border: 1px solid var(--border);\n  font-size: 12px;\n  color: var(--text-3);\n  margin-top: 8px;\n}\n.price-preview strong { color: var(--text); }\n.price-preview .retail { color: var(--green); font-weight: 700; font-size: 14px; }\n\n/* ── Qty badge ── */\n.qty-preview {\n  background: var(--green-light);\n  border: 1px solid var(--green-border);\n  border-radius: var(--r);\n  padding: 14px 18px;\n  display: flex; align-items: center; gap: 16px;\n  margin-top: 4px;\n}\n.qty-number {\n  font-size: 40px;\n  font-weight: 700;\n  color: var(--green);\n  letter-spacing: -.04em;\n  line-height: 1;\n  font-variant-numeric: tabular-nums;\n}\n.qty-detail { font-size: 12px; color: var(--text-3); margin-top: 3px; }\n\n/* ── Live pricing bar ── */\n.pricing-bar {\n  background: var(--blue-light);\n  border: 1px solid var(--blue-border);\n  border-radius: var(--r);\n  padding: 14px 16px;\n  margin-bottom: 16px;\n}\n.pricing-bar-label {\n  font-size: 10px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: .08em;\n  color: var(--blue);\n  margin-bottom: 10px;\n}\n\n/* ── Table ── */\n.data-table { width: 100%; border-collapse: collapse; font-size: 12px; }\n.data-table th {\n  padding: 8px 12px;\n  text-align: left;\n  font-size: 10px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: .07em;\n  color: var(--text-3);\n  border-bottom: 2px solid var(--border);\n  background: var(--surface-2);\n  white-space: nowrap;\n}\n.data-table td {\n  padding: 9px 12px;\n  border-bottom: 1px solid var(--border);\n  color: var(--text-2);\n}\n.data-table tr:last-child td { border-bottom: none; }\n.data-table tr:hover td { background: var(--surface-2); }\n.data-table .mono { font-family: 'JetBrains Mono', monospace; font-size: 11px; color: var(--text-3); }\n.data-table .price { color: var(--green); font-weight: 700; }\n.data-table .bold  { font-weight: 600; color: var(--text); }\n\n/* ── Export bar ── */\n.export-bar {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: var(--r-lg);\n  padding: 16px 20px;\n  display: flex; align-items: center;\n  justify-content: space-between;\n  gap: 16px;\n  flex-wrap: wrap;\n  box-shadow: var(--shadow-sm);\n}\n\n/* ── Modal backdrop ── */\n.modal-backdrop {\n  position: fixed; inset: 0;\n  background: rgba(0,0,0,.45);\n  backdrop-filter: blur(2px);\n  display: flex; align-items: center; justify-content: center;\n  padding: 1rem;\n  z-index: 200;\n}\n.modal-card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: var(--r-lg);\n  padding: 24px;\n  width: 100%;\n  max-width: 440px;\n  box-shadow: var(--shadow-lg);\n}\n.modal-title { font-size: 16px; font-weight: 700; letter-spacing: -.02em; margin-bottom: 4px; }\n.modal-sub { font-size: 12px; color: var(--text-3); margin-bottom: 20px; }\n\n/* ── Home page ── */\n.home-page {\n  min-height: 100vh;\n  display: flex; flex-direction: column;\n  align-items: center; justify-content: center;\n  padding: 2rem;\n  background: var(--bg);\n}\n.home-logo {\n  width: 80px; height: 80px;\n  border-radius: 20px;\n  box-shadow: var(--shadow-lg);\n  margin-bottom: 20px;\n}\n.home-brand {\n  font-size: 26px;\n  font-weight: 700;\n  letter-spacing: -.04em;\n  color: var(--text);\n  margin-bottom: 4px;\n}\n.home-tagline {\n  font-size: 13px;\n  color: var(--text-3);\n  margin-bottom: 40px;\n  letter-spacing: .01em;\n}\n.role-card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: var(--r-lg);\n  padding: 18px 20px;\n  width: 100%;\n  max-width: 380px;\n  cursor: pointer;\n  display: flex; align-items: center; gap: 16px;\n  margin-bottom: 10px;\n  transition: all .15s;\n  text-decoration: none;\n  box-shadow: var(--shadow-sm);\n}\n.role-card:hover {\n  border-color: var(--green);\n  box-shadow: 0 0 0 3px var(--green-light), var(--shadow);\n  transform: translateY(-1px);\n}\n.role-icon {\n  width: 44px; height: 44px;\n  border-radius: var(--r);\n  display: flex; align-items: center; justify-content: center;\n  font-size: 22px;\n  flex-shrink: 0;\n}\n.role-title { font-size: 14px; font-weight: 600; color: var(--text); letter-spacing: -.01em; }\n.role-desc  { font-size: 12px; color: var(--text-3); margin-top: 2px; }\n.home-credit {\n  margin-top: 48px;\n  font-size: 11px;\n  color: var(--text-4);\n  letter-spacing: .02em;\n}\n\n/* ── Mobile ── */\n@media (max-width: 520px) {\n  .stats-row { grid-template-columns: repeat(2,1fr); }\n  .stat-val  { font-size: 22px; }\n  .tabs      { width: 100%; }\n  .tab       { flex: 1; text-align: center; }\n  .container-wide { padding: 0 16px; }\n}\n\n/* ── Monospace for codes ── */\n.mono { font-family: 'JetBrains Mono', monospace; }\n", "src/app/page.tsx": "import Link from 'next/link';\nimport Image from 'next/image';\n\nexport default function Home() {\n  return (\n    <main className=\"home-page\">\n      <Image src=\"/logo.png\" alt=\"Choices For You\" width={80} height={80} className=\"home-logo\" priority />\n      <div className=\"home-brand\">Orders Manager</div>\n      <div className=\"home-tagline\">Choices For You · Vendor ordering system</div>\n\n      <Link href=\"/field\" className=\"role-card\">\n        <div className=\"role-icon\" style={{background:'#E8F2EC'}}>🧾</div>\n        <div>\n          <div className=\"role-title\">Order Entry</div>\n          <div className=\"role-desc\">Enter vendor items and order details</div>\n        </div>\n        <div style={{marginLeft:'auto',color:'var(--text-4)',fontSize:18}}>›</div>\n      </Link>\n\n      <Link href=\"/owner\" className=\"role-card\">\n        <div className=\"role-icon\" style={{background:'#EBF2FB'}}>🖥️</div>\n        <div>\n          <div className=\"role-title\">Management</div>\n          <div className=\"role-desc\">Review orders, approve items & export</div>\n        </div>\n        <div style={{marginLeft:'auto',color:'var(--text-4)',fontSize:18}}>›</div>\n      </Link>\n\n      <div className=\"home-credit\">Developed by Abdo Alasaadi</div>\n    </main>\n  );\n}\n", "src/app/field/page.tsx": "'use client';\nimport { useState, useEffect } from 'react';\nimport Image from 'next/image';\nimport type { Worker, Order, OrderItem } from '@/lib/types';\n\nconst EVEN_SIZES = Array.from({length:16},(_,i)=>String(28+i*2));\nconst LETTER_SIZES = ['XS','S','M','L','XL','2XL','3XL','4XL'];\nconst QUICK_COLORS = [\n  'Black','White','Gray','Navy','Beige','Brown','Green','Blue',\n  'Red','Khaki','Burgundy','Cream','Olive','Camel','Orange','Yellow','Purple','Pink'\n];\nconst DEFAULT_CATEGORIES = [\n  'Baggy Jeans','Coat','Dress Pants','Dress Shirt','Hat','Hoodie',\n  'Jacket','Jeans','Joggers','Knitwear','Pants','Scarf','Set',\n  'Shirt','Shoes','Shorts','Suit','Sweater','Sweatpants',\n  'Sweatshirt','T-Shirt','Tank Top','Tracksuit','Underwear'\n];\n\ntype Screen = 'login'|'orders'|'new-order'|'items'|'summary';\ntype SizeMode = 'letter'|'numeric';\ninterface Sel { value:string; count:number; }\n\nfunction addOrInc(arr:Sel[], v:string):Sel[] {\n  const e=arr.find(x=>x.value===v);\n  return e?arr.map(x=>x.value===v?{...x,count:x.count+1}:x):[...arr,{value:v,count:1}];\n}\nfunction dec(arr:Sel[], v:string):Sel[] {\n  return arr.map(x=>x.value===v?{...x,count:Math.max(0,x.count-1)}:x).filter(x=>x.count>0);\n}\nfunction total(arr:Sel[]):number { return arr.reduce((s,x)=>s+x.count,0); }\nfunction flat(arr:Sel[]):string[] { return arr.flatMap(x=>Array(x.count).fill(x.value)); }\n\n// Convert stored flat arrays back to Sel[] for editing\nfunction toSel(arr:string[]):Sel[] {\n  const map:Record<string,number>={};\n  arr.forEach(v=>{ map[v]=(map[v]||0)+1; });\n  return Object.entries(map).map(([value,count])=>({value,count}));\n}\n\nfunction SelTag({sel,onAdd,onRemove}:{sel:Sel;onAdd:()=>void;onRemove:()=>void}) {\n  return (\n    <span style={{display:'inline-flex',alignItems:'center',gap:4,padding:'4px 4px 4px 10px',\n      border:'1px solid var(--blue-border)',background:'var(--blue-bg)',color:'var(--blue)',\n      borderRadius:20,fontSize:13,fontWeight:500}}>\n      {sel.value}\n      {sel.count>1&&<span style={{background:'var(--blue)',color:'#fff',borderRadius:20,\n        padding:'1px 7px',fontSize:11,marginLeft:2}}>×{sel.count}</span>}\n      <span onClick={onAdd} style={{cursor:'pointer',width:24,height:24,borderRadius:'50%',\n        background:'var(--blue)',color:'#fff',display:'inline-flex',alignItems:'center',\n        justifyContent:'center',fontSize:17,marginLeft:2}}>+</span>\n      <span onClick={onRemove} style={{cursor:'pointer',width:24,height:24,borderRadius:'50%',\n        background:'var(--red-bg)',color:'var(--red)',border:'1px solid var(--red-border)',\n        display:'inline-flex',alignItems:'center',justifyContent:'center',fontSize:16}}>−</span>\n    </span>\n  );\n}\n\nexport default function FieldPage() {\n  const [screen, setScreen] = useState<Screen>('login');\n  const [worker, setWorker] = useState<Worker|null>(null);\n  const [pin, setPin] = useState('');\n  const [pinError, setPinError] = useState(false);\n  const [pinLoading, setPinLoading] = useState(false);\n\n  const [orders, setOrders] = useState<Order[]>([]);\n  const [currentOrder, setCurrentOrder] = useState<Order|null>(null);\n  const [items, setItems] = useState<OrderItem[]>([]);\n  const [vendors, setVendors] = useState<string[]>([]);\n  const [categories, setCategories] = useState<string[]>(DEFAULT_CATEGORIES);\n  const [toast, setToast] = useState('');\n  const [loading, setLoading] = useState(false);\n\n  // New order\n  const [orderName, setOrderName] = useState('');\n  const [orderDate, setOrderDate] = useState(new Date().toISOString().split('T')[0]);\n\n  // Item form\n  const [editingItem, setEditingItem] = useState<OrderItem|null>(null);\n  const [showItemList, setShowItemList] = useState(false);\n  const [vendor, setVendor] = useState('');\n  const [customVendor, setCustomVendor] = useState('');\n  const [code, setCode] = useState('');\n  const [category, setCategory] = useState('');\n  const [customCategory, setCustomCategory] = useState('');\n  const [colors, setColors] = useState<Sel[]>([]);\n  const [colorInput, setColorInput] = useState('');\n  const [sizeMode, setSizeMode] = useState<SizeMode>('letter');\n  const [sizes, setSizes] = useState<Sel[]>([]);\n  const [numericInput, setNumericInput] = useState('');\n  const [price, setPrice] = useState('');\n  const [notes, setNotes] = useState('');\n  const [errors, setErrors] = useState<Record<string,string>>({});\n\n  // Summary\n  const [shippingCost, setShippingCost] = useState('');\n  const [unreadNotifs, setUnreadNotifs] = useState(0);\n\n  function showToast(msg:string){ setToast(msg); setTimeout(()=>setToast(''),2500); }\n\n  useEffect(()=>{\n    fetch('/api/session').then(r=>r.json()).then(d=>{\n      if(d.registry) setVendors(Object.keys(d.registry).sort());\n    });\n  },[]);\n\n  async function handleLogin() {\n    setPinLoading(true); setPinError(false);\n    const res = await fetch('/api/session',{method:'POST',\n      headers:{'Content-Type':'application/json'},\n      body:JSON.stringify({action:'verify-worker',pin})});\n    const d = await res.json();\n    setPinLoading(false);\n    if(d.ok){ setWorker(d.worker); loadOrders(d.worker.id); loadNotifs(d.worker.id); setScreen('orders'); }\n    else setPinError(true);\n  }\n\n  async function loadOrders(workerId:string) {\n    const res = await fetch(`/api/orders?workerId=${workerId}`);\n    const d = await res.json();\n    if(d.orders) setOrders(d.orders.sort((a:Order,b:Order)=>\n      new Date(b.createdAt).getTime()-new Date(a.createdAt).getTime()));\n  }\n\n  async function loadNotifs(workerId:string) {\n    const res = await fetch(`/api/notifications?for=worker&workerId=${workerId}`);\n    const d = await res.json();\n    if(typeof d.unread==='number') setUnreadNotifs(d.unread);\n  }\n\n  async function handleCreateOrder() {\n    if(!orderName.trim()){ showToast('Enter order name'); return; }\n    setLoading(true);\n    const res = await fetch('/api/orders',{method:'POST',\n      headers:{'Content-Type':'application/json'},\n      body:JSON.stringify({action:'create',name:orderName.trim(),\n        startDate:orderDate,workerId:worker!.id,workerName:worker!.name})});\n    const d = await res.json();\n    setLoading(false);\n    if(d.order){\n      setCurrentOrder(d.order); setItems([]);\n      setOrderName(''); setScreen('items'); setShowItemList(false);\n      resetItemForm();\n    }\n  }\n\n  async function openOrder(order:Order) {\n    setCurrentOrder(order);\n    const res = await fetch(`/api/items?orderId=${order.id}`);\n    const d = await res.json();\n    setItems(d.items??[]);\n    setScreen('items'); setShowItemList(true); resetItemForm();\n  }\n\n  function resetItemForm() {\n    setEditingItem(null);\n    setVendor(''); setCustomVendor(''); setCode('');\n    setCategory(''); setCustomCategory('');\n    setColors([]); setColorInput('');\n    setSizes([]); setNumericInput('');\n    setPrice(''); setNotes(''); setErrors({});\n  }\n\n  function startEdit(item:OrderItem) {\n    setEditingItem(item);\n    setVendor(item.vendor);\n    setCode(item.code);\n    setCategory(item.category);\n    setColors(toSel(item.colors));\n    setSizes(toSel(item.sizes));\n    // detect size mode\n    const firstSize = item.sizes[0];\n    setSizeMode(!isNaN(Number(firstSize))&&Number(firstSize)>=28?'numeric':'letter');\n    setPrice(String(item.price));\n    setNotes(item.notes);\n    setErrors({});\n    setShowItemList(false);\n  }\n\n  async function handleSaveItem() {\n    const errs:Record<string,string>={};\n    const finalVendor = vendor==='__new__'?customVendor.trim():vendor;\n    const szArr = flat(sizes);\n    if(!finalVendor) errs.vendor='Select a vendor';\n    if(!code.trim()) errs.code='Enter item code';\n    if(!category) errs.category='Select category';\n    if(colors.length===0) errs.colors='Add at least one color';\n    if(szArr.length===0) errs.sizes='Select at least one size';\n    if(!price||Number(price)<=0) errs.price='Enter valid price';\n    setErrors(errs);\n    if(Object.keys(errs).length>0) return;\n\n    const autoQty = total(colors)*total(sizes);\n    setLoading(true);\n\n    if(editingItem) {\n      // EDIT existing\n      const updated:OrderItem = {\n        ...editingItem,\n        vendor:finalVendor, code:code.trim(), category,\n        colors:flat(colors), sizes:szArr,\n        price:Number(price), qty:autoQty||1, notes,\n      };\n      const res = await fetch('/api/items',{method:'PATCH',\n        headers:{'Content-Type':'application/json'},body:JSON.stringify(updated)});\n      setLoading(false);\n      if(res.ok){\n        setItems(prev=>prev.map(i=>i.id===updated.id?updated:i));\n        resetItemForm(); setShowItemList(true);\n        showToast('✓ Item updated');\n      } else showToast('Error updating item');\n    } else {\n      // NEW item\n      const res = await fetch('/api/items',{method:'POST',\n        headers:{'Content-Type':'application/json'},\n        body:JSON.stringify({orderId:currentOrder!.id,workerId:worker?.id||'',vendor:finalVendor,\n          code:code.trim(),category,colors:flat(colors),sizes:szArr,\n          price:Number(price),qty:autoQty||1,notes})});\n      const d = await res.json();\n      setLoading(false);\n      if(d.item){\n        setItems(prev=>[d.item,...prev]);\n        resetItemForm();\n        showToast('✓ Item saved — add next');\n      } else showToast('Error: '+d.error);\n    }\n  }\n\n  async function handleDeleteItem(id:string) {\n    if(!confirm('Remove this item?')) return;\n    await fetch('/api/items',{method:'DELETE',\n      headers:{'Content-Type':'application/json'},body:JSON.stringify({id})});\n    setItems(prev=>prev.filter(i=>i.id!==id));\n    showToast('Item removed');\n  }\n\n  async function handleSubmitOrder() {\n    if(!shippingCost||Number(shippingCost)<0){ showToast('Enter shipping cost (0 if none)'); return; }\n    setLoading(true);\n    const totalValue = items.reduce((s,i)=>s+i.price*i.qty,0);\n    const shipping = Number(shippingCost);\n    const commission = parseFloat((totalValue*0.03).toFixed(2));\n    const totalOrderCost = parseFloat((totalValue+shipping+commission).toFixed(2));\n    const updated:Order = {\n      ...currentOrder!,\n      shippingCost:shipping,\n      workerCommission:commission,\n      totalOrderCost,\n      status:'submitted',\n    };\n    await fetch('/api/orders',{method:'POST',\n      headers:{'Content-Type':'application/json'},\n      body:JSON.stringify({action:'update',order:updated})});\n    setLoading(false);\n    setCurrentOrder(updated);\n    if(worker) loadOrders(worker.id);\n    showToast('✓ Order submitted!');\n    setTimeout(()=>setScreen('orders'),1500);\n  }\n\n  const autoQty = total(colors)*total(sizes);\n\n  // Summary calculations\n  const totalPurchaseValue = items.reduce((s,i)=>s+i.price*i.qty,0);\n  const commission = parseFloat((totalPurchaseValue*0.03).toFixed(2));\n  const vendorSummary = items.reduce((map,item)=>{\n    if(!map[item.vendor]) map[item.vendor]={packs:0,units:0,value:0};\n    map[item.vendor].packs++;\n    map[item.vendor].units+=item.qty;\n    map[item.vendor].value+=item.price*item.qty;\n    return map;\n  },{} as Record<string,{packs:number;units:number;value:number}>);\n\n  // ── LOGIN ──\n  if(screen==='login') return (\n    <main className=\"login-page\">\n      <div className=\"login-card\">\n        <div className=\"login-logo\">\n          <Image src=\"/logo.png\" alt=\"Choices For You\" width={72} height={72}\n            style={{borderRadius:18,boxShadow:'0 8px 32px rgba(0,0,0,.14)',marginBottom:16}} />\n          <div className=\"login-brand\">Orders Manager</div>\n          <div className=\"login-sub\">Order Entry · Choices For You</div>\n        </div>\n        <div className=\"login-form\">\n          <div className=\"field\">\n            <label className=\"label\">Your PIN</label>\n            <input type=\"password\" inputMode=\"numeric\" placeholder=\"••••\"\n              value={pin} onChange={e=>setPin(e.target.value)}\n              onKeyDown={e=>e.key==='Enter'&&handleLogin()} autoFocus\n              className=\"login-pin-input\"/>\n            {pinError&&<div className=\"field-error\">Incorrect PIN — try again</div>}\n          </div>\n          <button className=\"btn btn-primary btn-lg btn-full\"\n            onClick={handleLogin} disabled={pinLoading}>\n            {pinLoading?'Verifying...':'Sign in'}\n          </button>\n          <div className=\"login-switch\">\n            Are you the manager?&nbsp;\n            <a onClick={()=>window.location.href='/owner'}>Sign in to Management instead</a>\n          </div>\n        </div>\n      </div>\n      {toast&&<div className=\"toast-wrap\"><div className=\"toast\">{toast}</div></div>}\n    </main>\n  );\n\n  // ── ORDERS LIST ──\n  if(screen==='orders') return (\n    <div className=\"page\">\n      <div className=\"header\">\n        <div className=\"container\">\n          <div className=\"header-inner\">\n            <div style={{display:'flex',alignItems:'center',gap:8}}>\n              <Image src=\"/logo.png\" alt=\"logo\" width={28} height={28} style={{borderRadius:6,flexShrink:0}} />\n              <div className=\"header-title\">👋 {worker?.name}</div>\n            </div>\n            <div style={{display:'flex',gap:6,alignItems:'center'}}>\n              {unreadNotifs>0&&(\n                <button className=\"btn btn-sm\" style={{position:'relative',background:'var(--red-light)',borderColor:'var(--red-border)',color:'var(--red)'}}\n                  onClick={async()=>{\n                    await fetch('/api/notifications',{method:'POST',headers:{'Content-Type':'application/json'},\n                      body:JSON.stringify({action:'mark-read',for:'worker',workerId:worker?.id})});\n                    setUnreadNotifs(0);\n                    if(worker) loadOrders(worker.id);\n                  }}>\n                  🔔 {unreadNotifs}\n                </button>\n              )}\n              <a href=\"/\" className=\"btn btn-sm\" title=\"Home\">🏠</a>\n              <button className=\"btn btn-sm\" onClick={()=>{setWorker(null);setPin('');setScreen('login')}}>Sign out</button>\n            </div>\n          </div>\n        </div>\n      </div>\n      <div className=\"container\" style={{paddingTop:16,paddingBottom:80}}>\n        <button className=\"btn btn-primary\"\n          style={{width:'100%',justifyContent:'center',padding:14,fontSize:15,marginBottom:20}}\n          onClick={()=>setScreen('new-order')}>\n          + Start new order\n        </button>\n        {orders.length===0?(\n          <div className=\"empty\"><div className=\"empty-icon\">📦</div><div className=\"empty-text\">No orders yet</div></div>\n        ):(\n          orders.map(order=>(\n            <div key={order.id} className=\"item-card\"\n              style={{cursor:order.status!=='imported'?'pointer':'default',opacity:order.status==='imported'?.7:1}}\n              onClick={()=>order.status!=='imported'&&openOrder(order)}>\n              <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:8}}>\n                <div>\n                  <div style={{fontWeight:600,fontSize:15}}>{order.name}</div>\n                  <div style={{fontSize:12,color:'var(--text-2)',marginTop:3}}>\n                    Started {order.startDate} · {order.itemCount} items\n                  </div>\n                  <div style={{fontSize:12,color:'var(--text-2)'}}>\n                    Purchase value: ${order.totalValue.toFixed(2)}\n                    {order.shippingCost>0&&` · Shipping: $${order.shippingCost.toFixed(2)}`}\n                    {order.workerCommission>0&&` · Your commission: $${order.workerCommission.toFixed(2)}`}\n                  </div>\n                  {order.totalOrderCost>0&&(\n                    <div style={{fontSize:12,fontWeight:600,marginTop:2}}>\n                      Total order cost: ${order.totalOrderCost.toFixed(2)}\n                    </div>\n                  )}\n                </div>\n                <span className={`badge ${order.status==='open'?'badge-pending':order.status==='submitted'?'badge-info':'badge-approved'}`}>\n                  {order.status}\n                </span>\n              </div>\n              {order.status==='imported'&&<div style={{fontSize:11,color:'var(--text-2)',marginTop:6}}>Closed — imported to POS</div>}\n            </div>\n          ))\n        )}\n      </div>\n      {toast&&<div className=\"toast-wrap\"><div className=\"toast\">{toast}</div></div>}\n    </div>\n  );\n\n  // ── NEW ORDER ──\n  if(screen==='new-order') return (\n    <div className=\"page\">\n      <div className=\"header\">\n        <div className=\"container\">\n          <div className=\"header-inner\">\n            <div><div className=\"header-title\">New order</div></div>\n            <button className=\"btn btn-sm\" onClick={()=>setScreen('orders')}>← Back</button>\n          </div>\n        </div>\n      </div>\n      <div className=\"container\" style={{paddingTop:16}}>\n        <div className=\"card\">\n          <div className=\"card-title\">Order details</div>\n          <div className=\"field\">\n            <label className=\"label\">Order name</label>\n            <input type=\"text\" placeholder=\"e.g. Punch Summer 2025\"\n              value={orderName} onChange={e=>setOrderName(e.target.value)}\n              onKeyDown={e=>e.key==='Enter'&&handleCreateOrder()} autoFocus/>\n          </div>\n          <div className=\"field\" style={{marginBottom:0}}>\n            <label className=\"label\">Start date</label>\n            <input type=\"date\" value={orderDate} onChange={e=>setOrderDate(e.target.value)}/>\n          </div>\n        </div>\n        <button className=\"btn btn-primary\"\n          style={{width:'100%',justifyContent:'center',padding:14,fontSize:15,marginTop:14}}\n          onClick={handleCreateOrder} disabled={loading}>\n          {loading?'Creating...':'Create order & add items →'}\n        </button>\n      </div>\n      {toast&&<div className=\"toast-wrap\"><div className=\"toast\">{toast}</div></div>}\n    </div>\n  );\n\n  // ── ORDER SUMMARY + SHIPPING ──\n  if(screen==='summary') return (\n    <div className=\"page\">\n      <div className=\"header\">\n        <div className=\"container\">\n          <div className=\"header-inner\">\n            <div>\n              <div className=\"header-title\">Order summary</div>\n              <div className=\"header-sub\">{currentOrder?.name}</div>\n            </div>\n            <button className=\"btn btn-sm\" onClick={()=>setScreen('items')}>← Back</button>\n          </div>\n        </div>\n      </div>\n      <div className=\"container\" style={{paddingTop:16,paddingBottom:80}}>\n\n        {/* Vendor breakdown */}\n        <div className=\"card\" style={{marginBottom:12}}>\n          <div className=\"card-title\">By vendor</div>\n          {Object.entries(vendorSummary).sort((a,b)=>b[1].value-a[1].value).map(([v,d])=>(\n            <div key={v} style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',\n              padding:'8px 0',borderBottom:'1px solid var(--border)',fontSize:13}}>\n              <div>\n                <strong>{v}</strong>\n                <div style={{fontSize:11,color:'var(--text-2)',marginTop:2}}>\n                  {d.packs} pack{d.packs!==1?'s':''} · {d.units} unit{d.units!==1?'s':''}\n                </div>\n              </div>\n              <span style={{fontWeight:500}}>${d.value.toFixed(2)}</span>\n            </div>\n          ))}\n          <div style={{display:'flex',justifyContent:'space-between',paddingTop:10,fontWeight:600,fontSize:14}}>\n            <span>Total purchase value</span>\n            <span>${totalPurchaseValue.toFixed(2)}</span>\n          </div>\n        </div>\n\n        {/* Commission */}\n        <div className=\"card\" style={{marginBottom:12,background:'var(--blue-bg)',border:'1px solid var(--blue-border)'}}>\n          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>\n            <div>\n              <div style={{fontWeight:600,color:'var(--blue)'}}>Your commission (3%)</div>\n              <div style={{fontSize:12,color:'var(--text-2)',marginTop:2}}>3% of ${totalPurchaseValue.toFixed(2)} purchase value</div>\n            </div>\n            <div style={{fontSize:24,fontWeight:700,color:'var(--blue)'}}>${commission.toFixed(2)}</div>\n          </div>\n        </div>\n\n        {/* Shipping input */}\n        <div className=\"card\" style={{marginBottom:12}}>\n          <div className=\"card-title\">Shipping cost</div>\n          <input type=\"number\" inputMode=\"decimal\" placeholder=\"0.00\" step=\"0.01\" min=\"0\"\n            value={shippingCost} onChange={e=>setShippingCost(e.target.value)}\n            style={{fontSize:18}} autoFocus/>\n          <div style={{fontSize:12,color:'var(--text-2)',marginTop:6}}>Total shipping cost paid for this order</div>\n        </div>\n\n        {/* Total order cost preview */}\n        {shippingCost!==''&&(\n          <div className=\"card\" style={{marginBottom:16,background:'var(--green-bg)',border:'1px solid var(--green-border)'}}>\n            <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>\n              <div>\n                <div style={{fontWeight:600,color:'var(--green)',fontSize:15}}>Total order cost</div>\n                <div style={{fontSize:12,color:'var(--text-2)',marginTop:2}}>\n                  ${totalPurchaseValue.toFixed(2)} + ${Number(shippingCost||0).toFixed(2)} shipping + ${commission.toFixed(2)} commission\n                </div>\n              </div>\n              <div style={{fontSize:26,fontWeight:700,color:'var(--green)'}}>\n                ${(totalPurchaseValue+Number(shippingCost||0)+commission).toFixed(2)}\n              </div>\n            </div>\n          </div>\n        )}\n\n        <button className=\"btn btn-success\"\n          style={{width:'100%',justifyContent:'center',padding:14,fontSize:15}}\n          onClick={handleSubmitOrder} disabled={loading}>\n          {loading?'Submitting...':'Submit to owner ✓'}\n        </button>\n      </div>\n      {toast&&<div className=\"toast-wrap\"><div className=\"toast\">{toast}</div></div>}\n    </div>\n  );\n\n  // ── ITEMS SCREEN ──\n  return (\n    <div className=\"page\">\n      <div className=\"header\">\n        <div className=\"container\">\n          <div className=\"header-inner\">\n            <div>\n              <div className=\"header-title\">{currentOrder?.name}</div>\n              <div className=\"header-sub\">{items.length} items · {worker?.name}</div>\n            </div>\n            <div style={{display:'flex',gap:6}}>\n              <button className=\"btn btn-sm\" onClick={()=>setScreen('orders')}>← Back</button>\n              <button className={`btn btn-sm ${showItemList?'btn-primary':''}`}\n                onClick={()=>{setShowItemList(true);resetItemForm();}}>List ({items.length})</button>\n              <button className={`btn btn-sm ${!showItemList&&!editingItem?'btn-primary':''}`}\n                onClick={()=>{setShowItemList(false);resetItemForm();}}>+ Add</button>\n              <button className=\"btn btn-sm btn-success\" onClick={()=>setScreen('summary')}>Review & Submit →</button>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <div className=\"container\" style={{paddingTop:16,paddingBottom:80}}>\n\n        {/* ITEM LIST — grouped by vendor */}\n        {showItemList&&(\n          items.length===0?(\n            <div className=\"empty\">\n              <div className=\"empty-icon\">📋</div>\n              <div className=\"empty-text\">No items yet — tap + Add</div>\n            </div>\n          ):( ()=>{\n            // Group by vendor, preserve latest-first within each vendor\n            const sorted = [...items].sort((a,b)=>a.vendor.localeCompare(b.vendor)||new Date(b.createdAt).getTime()-new Date(a.createdAt).getTime());\n            const vendorGroups = sorted.reduce((map,item)=>{\n              if(!map[item.vendor]) map[item.vendor]=[];\n              map[item.vendor].push(item);\n              return map;\n            },{} as Record<string,OrderItem[]>);\n            return Object.entries(vendorGroups).map(([v,vItems])=>(\n              <div key={v} style={{marginBottom:16}}>\n                <div style={{fontSize:11,fontWeight:600,textTransform:'uppercase',\n                  letterSpacing:'.06em',color:'var(--text-2)',\n                  padding:'4px 2px',marginBottom:6,borderBottom:'1px solid var(--border)'}}>\n                  {v} · {vItems.length} pack{vItems.length!==1?'s':''}\n                </div>\n                {vItems.map(item=>(\n                  <div key={item.id} className=\"item-card\" style={{marginBottom:8}}>\n                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:8}}>\n                      <div style={{flex:1,minWidth:0}}>\n                        <div style={{fontWeight:600,fontFamily:'monospace',fontSize:14}}>{item.code}</div>\n                        <div style={{fontSize:12,color:'var(--text-2)',marginTop:2}}>\n                          {item.category} · {item.colors.join(', ')} · {item.sizes.join('/')}\n                        </div>\n                        <div style={{fontSize:12,color:'var(--text-2)'}}>${item.price} · {item.qty} units</div>\n                        {item.ownerNote&&<div style={{fontSize:11,color:'var(--amber)',marginTop:3}}>Owner: {item.ownerNote}</div>}\n                      </div>\n                      <div style={{display:'flex',gap:6,alignItems:'center',flexShrink:0}}>\n                        <span className={`badge badge-${item.status}`}>{item.status}</span>\n                        <button className=\"btn btn-sm\" onClick={()=>startEdit(item)}>Edit</button>\n                        <button className=\"btn btn-sm\" style={{color:'var(--red)',borderColor:'var(--red-border)'}}\n                          onClick={()=>handleDeleteItem(item.id)}>✕</button>\n                      </div>\n                    </div>\n                  </div>\n                ))}\n              </div>\n            ));\n          })()\n        )}\n\n        {/* ADD / EDIT FORM */}\n        {!showItemList&&(\n          <>\n            {editingItem&&(\n              <div style={{background:'var(--amber-bg)',border:'1px solid var(--amber-border)',\n                borderRadius:'var(--radius)',padding:'10px 14px',marginBottom:12,\n                display:'flex',justifyContent:'space-between',alignItems:'center'}}>\n                <div style={{fontSize:13,color:'var(--amber)',fontWeight:500}}>\n                  Editing: {editingItem.vendor} · {editingItem.code}\n                </div>\n                <button className=\"btn btn-sm\" onClick={()=>{resetItemForm();setShowItemList(true);}}>Cancel</button>\n              </div>\n            )}\n\n            {/* 1. VENDOR */}\n            <div className=\"card\">\n              <div className=\"card-title\">1 · Vendor</div>\n              <select value={vendor} onChange={e=>setVendor(e.target.value)}>\n                <option value=\"\">Select vendor...</option>\n                {vendors.map(v=><option key={v} value={v}>{v}</option>)}\n                <option value=\"__new__\">+ New vendor</option>\n              </select>\n              {vendor==='__new__'&&<input type=\"text\" style={{marginTop:6}} placeholder=\"Vendor name\"\n                value={customVendor} onChange={e=>setCustomVendor(e.target.value)}/>}\n              {errors.vendor&&<div className=\"field-error\">{errors.vendor}</div>}\n            </div>\n\n            {/* 2. ITEM CODE */}\n            <div className=\"card\">\n              <div className=\"card-title\">2 · Item code</div>\n              <input type=\"text\" placeholder=\"e.g. 8855 or P-26.113\" value={code}\n                onChange={e=>setCode(e.target.value)}\n                style={{fontSize:16,fontFamily:'monospace'}}/>\n              {errors.code&&<div className=\"field-error\">{errors.code}</div>}\n            </div>\n\n            {/* 3. CATEGORY */}\n            <div className=\"card\">\n              <div className=\"card-title\">3 · Category</div>\n              <div className=\"chip-group\" style={{marginBottom:10}}>\n                {categories.map(c=>(\n                  <div key={c} className={`chip ${category===c?'active':''}`}\n                    onClick={()=>setCategory(c)}>{c}</div>\n                ))}\n              </div>\n              <div style={{display:'flex',gap:8}}>\n                <input type=\"text\" placeholder=\"Add new category...\" value={customCategory}\n                  onChange={e=>setCustomCategory(e.target.value)}\n                  onKeyDown={e=>{if(e.key==='Enter'&&customCategory.trim()){\n                    const v=customCategory.trim();\n                    if(!categories.includes(v)) setCategories(prev=>[...prev,v].sort());\n                    setCategory(v); setCustomCategory('');\n                  }}} style={{flex:1}}/>\n                <button className=\"btn btn-sm btn-primary\" onClick={()=>{\n                  const v=customCategory.trim(); if(!v) return;\n                  if(!categories.includes(v)) setCategories(prev=>[...prev,v].sort());\n                  setCategory(v); setCustomCategory('');\n                }}>Add</button>\n              </div>\n              {errors.category&&<div className=\"field-error\" style={{marginTop:6}}>{errors.category}</div>}\n            </div>\n\n            {/* 4. COLORS */}\n            <div className=\"card\">\n              <div className=\"card-title\">4 · Colors — tap to add, + for more packs</div>\n              <div style={{display:'flex',gap:8,marginBottom:10}}>\n                <input type=\"text\" placeholder=\"Type color, Enter to add\" value={colorInput}\n                  onChange={e=>setColorInput(e.target.value)}\n                  onKeyDown={e=>{if(e.key==='Enter'&&colorInput.trim()){\n                    setColors(prev=>addOrInc(prev,colorInput.trim())); setColorInput('');\n                  }}} style={{flex:1}}/>\n                <button className=\"btn btn-sm btn-primary\" onClick={()=>{\n                  if(colorInput.trim()){setColors(prev=>addOrInc(prev,colorInput.trim()));setColorInput('');}\n                }}>Add</button>\n              </div>\n              <div className=\"chip-group\" style={{marginBottom:10}}>\n                {QUICK_COLORS.map(c=><div key={c} className=\"chip\"\n                  onClick={()=>setColors(prev=>addOrInc(prev,c))}>{c}</div>)}\n              </div>\n              {colors.length>0&&<div style={{display:'flex',flexWrap:'wrap',gap:8,marginTop:4}}>\n                {colors.map(sel=><SelTag key={sel.value} sel={sel}\n                  onAdd={()=>setColors(prev=>addOrInc(prev,sel.value))}\n                  onRemove={()=>setColors(prev=>dec(prev,sel.value))}/>)}\n              </div>}\n              {errors.colors&&<div className=\"field-error\" style={{marginTop:6}}>{errors.colors}</div>}\n            </div>\n\n            {/* 5. SIZES */}\n            <div className=\"card\">\n              <div className=\"card-title\">5 · Sizes — tap to add, + for more packs</div>\n              <div style={{display:'flex',gap:8,marginBottom:12}}>\n                <button className={`btn btn-sm ${sizeMode==='letter'?'btn-primary':''}`}\n                  onClick={()=>{setSizeMode('letter');setSizes([]);}}>S / M / L</button>\n                <button className={`btn btn-sm ${sizeMode==='numeric'?'btn-primary':''}`}\n                  onClick={()=>{setSizeMode('numeric');setSizes([]);}}>28 / 30 / 32</button>\n              </div>\n              {sizeMode==='letter'&&(\n                <div className=\"chip-group\" style={{marginBottom:sizes.length?10:0}}>\n                  {LETTER_SIZES.map(s=><div key={s} className=\"chip\"\n                    onClick={()=>setSizes(prev=>addOrInc(prev,s))}>{s}</div>)}\n                </div>\n              )}\n              {sizeMode==='numeric'&&(<>\n                <div className=\"chip-group\" style={{marginBottom:8,flexWrap:'wrap'}}>\n                  {EVEN_SIZES.map(s=><div key={s} className=\"chip\"\n                    onClick={()=>setSizes(prev=>addOrInc(prev,s))}>{s}</div>)}\n                </div>\n                <div style={{display:'flex',gap:8,marginBottom:sizes.length?10:0}}>\n                  <input type=\"text\" inputMode=\"numeric\" placeholder=\"Or type: 29,31,33\"\n                    value={numericInput} onChange={e=>setNumericInput(e.target.value)}\n                    onKeyDown={e=>{if(e.key==='Enter'){\n                      numericInput.split(',').map(s=>s.trim()).filter(Boolean)\n                        .forEach(s=>setSizes(prev=>addOrInc(prev,s)));\n                      setNumericInput('');\n                    }}} style={{flex:1}}/>\n                  <button className=\"btn btn-sm btn-primary\" onClick={()=>{\n                    numericInput.split(',').map(s=>s.trim()).filter(Boolean)\n                      .forEach(s=>setSizes(prev=>addOrInc(prev,s)));\n                    setNumericInput('');\n                  }}>Add</button>\n                </div>\n              </>)}\n              {sizes.length>0&&<div style={{display:'flex',flexWrap:'wrap',gap:8}}>\n                {sizes.map(sel=><SelTag key={sel.value} sel={sel}\n                  onAdd={()=>setSizes(prev=>addOrInc(prev,sel.value))}\n                  onRemove={()=>setSizes(prev=>dec(prev,sel.value))}/>)}\n              </div>}\n              {errors.sizes&&<div className=\"field-error\" style={{marginTop:6}}>{errors.sizes}</div>}\n            </div>\n\n            {/* 6. PRICE */}\n            <div className=\"card\">\n              <div className=\"card-title\">6 · Unit price (USD)</div>\n              <input type=\"number\" inputMode=\"decimal\" placeholder=\"0.00\" step=\"0.5\" min=\"0\"\n                value={price} onChange={e=>setPrice(e.target.value)}/>\n              {errors.price&&<div className=\"field-error\">{errors.price}</div>}\n            </div>\n\n            {/* QTY PREVIEW */}\n            {autoQty>0&&(\n              <div className=\"card\" style={{background:'var(--green-bg)',border:'1px solid var(--green-border)'}}>\n                <div style={{display:'flex',alignItems:'center',gap:14}}>\n                  <div style={{fontSize:36,fontWeight:700,color:'var(--green)'}}>{autoQty}</div>\n                  <div>\n                    <div style={{fontWeight:600,color:'var(--green)',fontSize:15}}>Total units in this pack</div>\n                    <div style={{fontSize:12,color:'var(--text-2)',marginTop:2}}>\n                      {total(colors)} color units × {total(sizes)} size units = {autoQty} units\n                    </div>\n                  </div>\n                </div>\n                <div style={{marginTop:8,fontSize:12,color:'var(--text-2)',display:'flex',gap:16,flexWrap:'wrap'}}>\n                  <span>Colors: {colors.map(c=>c.count>1?`${c.value}×${c.count}`:c.value).join(', ')}</span>\n                  <span>Sizes: {sizes.map(s=>s.count>1?`${s.value}×${s.count}`:s.value).join(', ')}</span>\n                </div>\n              </div>\n            )}\n\n            {/* NOTE */}\n            <div className=\"card\">\n              <div className=\"card-title\">Note to owner (optional)</div>\n              <input type=\"text\" placeholder=\"Anything the owner should know...\"\n                value={notes} onChange={e=>setNotes(e.target.value)}/>\n            </div>\n\n            <div style={{display:'flex',gap:10,marginTop:14}}>\n              <button className=\"btn\" onClick={()=>{resetItemForm();if(editingItem)setShowItemList(true);}}>\n                {editingItem?'Cancel':'Clear'}\n              </button>\n              <button className=\"btn btn-primary\"\n                style={{flex:1,justifyContent:'center',padding:12}}\n                onClick={handleSaveItem} disabled={loading}>\n                {loading?'Saving...':editingItem?'Update item ✓':'Save item →'}\n              </button>\n            </div>\n          </>\n        )}\n      </div>\n      {toast&&<div className=\"toast-wrap\"><div className=\"toast\">{toast}</div></div>}\n    </div>\n  );\n}\n", "src/app/owner/page.tsx": "'use client';\nimport { useState, useEffect, useCallback } from 'react';\nimport Image from 'next/image';\nimport type { Order, OrderItem, SessionSettings, Worker } from '@/lib/types';\nimport { calcUnitCost, calcRetailPrice } from '@/lib/pricing';\n\ntype Tab = 'orders' | 'items' | 'workers' | 'settings';\n\nexport default function OwnerPage() {\n  const [authed, setAuthed] = useState(false);\n  const [pin, setPin] = useState('');\n  const [pinError, setPinError] = useState(false);\n  const [pinLoading, setPinLoading] = useState(false);\n\n  const [orders, setOrders] = useState<Order[]>([]);\n  const [selectedOrder, setSelectedOrder] = useState<Order|null>(null);\n  const [items, setItems] = useState<OrderItem[]>([]);\n  const [settings, setSettings] = useState<SessionSettings>({tax:6,markup:3.5,shipping:6.1,ownerPin:'1234'});\n  const [registry, setRegistry] = useState<Record<string,number>>({});\n  const [workers, setWorkers] = useState<Worker[]>([]);\n  const [tab, setTab] = useState<Tab>('orders');\n  const [filterStatus, setFilterStatus] = useState('');\n  const [toast, setToast] = useState('');\n  const [exporting, setExporting] = useState(false);\n  const [savingSettings, setSavingSettings] = useState(false);\n  const [flagModal, setFlagModal] = useState<{item:OrderItem}|null>(null);\n  const [flagNote, setFlagNote] = useState('');\n  const [editModal, setEditModal] = useState<{item:OrderItem}|null>(null);\n  const [editPrice, setEditPrice] = useState('');\n  const [editNotes, setEditNotes] = useState('');\n  const [editOwnerNote, setEditOwnerNote] = useState('');\n  // Worker form\n  const [newWorkerName, setNewWorkerName] = useState('');\n  const [newWorkerPin, setNewWorkerPin] = useState('');\n  const [unreadNotifs, setUnreadNotifs] = useState(0);\n\n  function showToast(msg: string) { setToast(msg); setTimeout(()=>setToast(''),2500); }\n\n  async function verifyPin() {\n    setPinLoading(true); setPinError(false);\n    const res = await fetch('/api/session',{method:'POST',headers:{'Content-Type':'application/json'},\n      body:JSON.stringify({action:'verify-owner',pin})});\n    const d = await res.json();\n    setPinLoading(false);\n    if(d.ok){ setAuthed(true); loadAll(); loadNotifs(); }\n    else setPinError(true);\n  }\n\n  async function loadNotifs() {\n    const res = await fetch('/api/notifications?for=owner');\n    const d = await res.json();\n    if(typeof d.unread==='number') setUnreadNotifs(d.unread);\n  }\n\n  const loadAll = useCallback(async()=>{\n    const [ordersRes, sessionRes] = await Promise.all([\n      fetch('/api/orders').then(r=>r.json()),\n      fetch('/api/session').then(r=>r.json()),\n    ]);\n    if(ordersRes.orders) setOrders(ordersRes.orders.sort((a:Order,b:Order)=>\n      new Date(b.createdAt).getTime()-new Date(a.createdAt).getTime()));\n    if(sessionRes.settings) setSettings(sessionRes.settings);\n    if(sessionRes.registry) setRegistry(sessionRes.registry);\n    if(sessionRes.workers) setWorkers(sessionRes.workers);\n  },[]);\n\n  useEffect(()=>{ if(!authed) return;\n    const iv = setInterval(()=>{\n      fetch('/api/orders').then(r=>r.json()).then(d=>{\n        if(d.orders) setOrders(d.orders.sort((a:Order,b:Order)=>\n          new Date(b.createdAt).getTime()-new Date(a.createdAt).getTime()));\n      });\n      fetch('/api/notifications?for=owner').then(r=>r.json()).then(d=>{\n        if(typeof d.unread==='number') setUnreadNotifs(d.unread);\n      });\n    },30000);\n    return ()=>clearInterval(iv);\n  },[authed]);\n\n  async function selectOrder(order: Order) {\n    setSelectedOrder(order);\n    const res = await fetch(`/api/items?orderId=${order.id}`);\n    const d = await res.json();\n    setItems(d.items ?? []);\n    setTab('items');\n  }\n\n  async function updateItemStatus(item: OrderItem, status: OrderItem['status'], ownerNote='') {\n    const updated = {...item, status, ownerNote};\n    setItems(prev=>prev.map(i=>i.id===updated.id?updated:i));\n    await fetch('/api/items',{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify(updated)});\n    showToast(status==='approved'?'✓ Approved':'⚑ Flagged');\n  }\n\n  async function deleteItem(id: string) {\n    if(!confirm('Remove this item?')) return;\n    setItems(prev=>prev.filter(i=>i.id!==id));\n    await fetch('/api/items',{method:'DELETE',headers:{'Content-Type':'application/json'},body:JSON.stringify({id})});\n    showToast('Item removed');\n  }\n\n  async function saveEditItem() {\n    if(!editModal) return;\n    const updated = {\n      ...editModal.item,\n      price: Number(editPrice) || editModal.item.price,\n      notes: editNotes,\n      ownerNote: editOwnerNote,\n    };\n    setItems(prev=>prev.map(i=>i.id===updated.id?updated:i));\n    await fetch('/api/items',{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify(updated)});\n    setEditModal(null);\n    showToast('✓ Item updated');\n  }\n\n  async function closeOrder(orderId: string) {\n    if(!confirm('Mark this order as Imported and close it?')) return;\n    await fetch('/api/orders',{method:'POST',headers:{'Content-Type':'application/json'},\n      body:JSON.stringify({action:'close',orderId})});\n    showToast('Order closed and marked Imported');\n    loadAll();\n  }\n\n  async function doExport() {\n    if(!selectedOrder) return;\n    setExporting(true);\n    try {\n      const res = await fetch(`/api/export?orderId=${selectedOrder.id}`);\n      if(!res.ok){ const d=await res.json(); throw new Error(d.error); }\n      const blob = await res.blob();\n      const url = URL.createObjectURL(blob);\n      const a = document.createElement('a'); a.href=url;\n      a.download=`SQUARE_${selectedOrder.name.replace(/\\s+/g,'_')}.csv`;\n      a.click(); URL.revokeObjectURL(url);\n      showToast('✓ CSV downloaded');\n    } catch(e:any){ showToast('Export failed: '+e.message); }\n    finally{ setExporting(false); }\n  }\n\n  async function saveSettings() {\n    setSavingSettings(true);\n    await fetch('/api/session',{method:'POST',headers:{'Content-Type':'application/json'},\n      body:JSON.stringify({action:'save-settings',settings})});\n    setSavingSettings(false); showToast('Settings saved');\n  }\n\n  async function addWorker() {\n    if(!newWorkerName.trim()||!newWorkerPin.trim()){ showToast('Enter name and PIN'); return; }\n    const newId = 'w_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);\n    const updated = [...workers, {id:newId, name:newWorkerName.trim(), pin:newWorkerPin.trim()}];\n    const res = await fetch('/api/session',{method:'POST',headers:{'Content-Type':'application/json'},\n      body:JSON.stringify({action:'save-workers',workers:updated})});\n    const d = await res.json();\n    if(d.ok){\n      const fresh = await fetch('/api/session').then(r=>r.json());\n      if(fresh.workers) setWorkers(fresh.workers);\n      setNewWorkerName(''); setNewWorkerPin('');\n      showToast('✓ Worker saved');\n    } else { showToast('Error saving worker'); }\n  }\n\n  async function removeWorker(id: string) {\n    if(!confirm('Remove this worker?')) return;\n    const updated = workers.filter(w=>w.id!==id);\n    await fetch('/api/session',{method:'POST',headers:{'Content-Type':'application/json'},\n      body:JSON.stringify({action:'save-workers',workers:updated})});\n    setWorkers(updated); showToast('Worker removed');\n  }\n\n  const filteredItems = items.filter(i=>!filterStatus||i.status===filterStatus)\n    .sort((a,b)=>new Date(b.createdAt).getTime()-new Date(a.createdAt).getTime());\n  const approvedCount = items.filter(i=>i.status==='approved').length;\n  const pendingCount  = items.filter(i=>i.status==='pending').length;\n  const flaggedCount  = items.filter(i=>i.status==='flagged').length;\n  const exportableRows = items.filter(i=>i.status!=='flagged').reduce((s,i)=>s+i.colors.length*i.sizes.length,0);\n\n  if(!authed) return (\n    <main className=\"login-page\">\n      <div className=\"login-card\">\n        <div className=\"login-logo\">\n          <Image src=\"/logo.png\" alt=\"Choices For You\" width={72} height={72}\n            style={{borderRadius:18,boxShadow:'0 8px 32px rgba(0,0,0,.14)',marginBottom:16}} />\n          <div className=\"login-brand\">Orders Manager</div>\n          <div className=\"login-sub\">Management · Choices For You</div>\n        </div>\n        <div className=\"login-form\">\n          <div className=\"field\">\n            <label className=\"label\">Management PIN</label>\n            <input type=\"password\" inputMode=\"numeric\" placeholder=\"••••\"\n              value={pin} onChange={e=>setPin(e.target.value)}\n              onKeyDown={e=>e.key==='Enter'&&verifyPin()}\n              className=\"login-pin-input\" autoFocus/>\n            {pinError&&<div className=\"field-error\">Incorrect PIN — try again</div>}\n          </div>\n          <button className=\"btn btn-primary btn-lg btn-full\"\n            onClick={verifyPin} disabled={pinLoading}>\n            {pinLoading?'Verifying...':'Sign in'}\n          </button>\n          <div className=\"login-switch\">\n            Field worker?&nbsp;\n            <a onClick={()=>window.location.href='/field'}>Sign in to Order Entry instead</a>\n          </div>\n        </div>\n      </div>\n    </main>\n  );\n\n  return (\n    <div className=\"page\">\n      <div className=\"header\">\n        <div className=\"container-wide\">\n          <div className=\"header-inner\">\n            <div style={{display:'flex',alignItems:'center',gap:8}}>\n              <Image src=\"/logo.png\" alt=\"logo\" width={28} height={28} style={{borderRadius:6,flexShrink:0}} />\n              <div className=\"header-title\">Management</div>\n            </div>\n            <div style={{display:'flex',gap:6,alignItems:'center'}}>\n              <span className=\"badge badge-info\">{orders.length}</span>\n              <button className=\"btn btn-sm\" onClick={()=>{loadAll();loadNotifs();showToast('Refreshed');}} title=\"Refresh\">↻</button>\n              {unreadNotifs>0&&(\n                <button className=\"btn btn-sm\" style={{background:'var(--red-light)',borderColor:'var(--red-border)',color:'var(--red)'}}\n                  onClick={async()=>{\n                    await fetch('/api/notifications',{method:'POST',headers:{'Content-Type':'application/json'},\n                      body:JSON.stringify({action:'mark-read',for:'owner'})});\n                    setUnreadNotifs(0);\n                  }}>\n                  🔔 {unreadNotifs} new\n                </button>\n              )}\n              <a href=\"/\" className=\"btn btn-sm\" title=\"Home\">🏠</a>\n              <button className=\"btn btn-sm\" onClick={()=>setAuthed(false)}>Exit</button>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <div className=\"container-wide\" style={{paddingTop:16,paddingBottom:40}}>\n        <div className=\"tabs\">\n          {(['orders','items','workers','settings'] as Tab[]).map(t=>(\n            <button key={t} className={`tab ${tab===t?'active':''}`} onClick={()=>setTab(t)}>\n              {t.charAt(0).toUpperCase()+t.slice(1)}\n              {t==='items'&&selectedOrder&&` — ${selectedOrder.name}`}\n            </button>\n          ))}\n        </div>\n\n        {/* ── ORDERS TAB ── */}\n        {tab==='orders'&&(\n          <>\n            <div style={{display:'flex',gap:8,marginBottom:12,flexWrap:'wrap'}}>\n              {(['','open','submitted','imported'] as const).map(s=>(\n                <button key={s} className={`btn btn-sm ${filterStatus===s?'btn-primary':''}`}\n                  onClick={()=>setFilterStatus(s)}>\n                  {s===''?'All':s.charAt(0).toUpperCase()+s.slice(1)}\n                </button>\n              ))}\n            </div>\n            {orders.filter(o=>!filterStatus||o.status===filterStatus).length===0?(\n              <div className=\"empty\"><div className=\"empty-icon\">📦</div><div className=\"empty-text\">No orders yet</div></div>\n            ):(\n              orders.filter(o=>!filterStatus||o.status===filterStatus).map(order=>(\n                <div key={order.id} className=\"item-card\" style={{cursor:'pointer'}} onClick={()=>selectOrder(order)}>\n                  <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start'}}>\n                    <div style={{flex:1,minWidth:0}}>\n                      <div style={{fontWeight:600,fontSize:15}}>{order.name}</div>\n                      <div style={{fontSize:12,color:'var(--text-2)',marginTop:3}}>\n                        {order.workerName} · Started {order.startDate} · {order.itemCount} items · ${order.totalValue.toFixed(0)} purchase value\n                      </div>\n                      {order.shippingCost>0&&<div style={{fontSize:12,color:'var(--text-2)'}}>Shipping: ${order.shippingCost}</div>}\n                    </div>\n                    <div style={{display:'flex',gap:8,alignItems:'center',flexShrink:0,marginLeft:10}}>\n                      <span className={`badge ${order.status==='open'?'badge-pending':order.status==='submitted'?'badge-info':'badge-approved'}`}>\n                        {order.status}\n                      </span>\n                      {order.status==='submitted'&&(\n                        <button className=\"btn btn-sm btn-success\" onClick={e=>{e.stopPropagation();closeOrder(order.id)}}>\n                          Mark imported\n                        </button>\n                      )}\n                    </div>\n                  </div>\n                </div>\n              ))\n            )}\n          </>\n        )}\n\n        {/* ── ITEMS TAB ── */}\n        {tab==='items'&&(\n          <>\n            {!selectedOrder?(\n              <div className=\"empty\"><div className=\"empty-icon\">👆</div><div className=\"empty-text\">Select an order from the Orders tab</div></div>\n            ):(\n              <>\n                {/* Status badges + filter */}\n                <div style={{display:'flex',gap:8,marginBottom:12,flexWrap:'wrap',alignItems:'center'}}>\n                  <span className=\"badge badge-approved\">{approvedCount} approved</span>\n                  <span className=\"badge badge-pending\">{pendingCount} pending</span>\n                  {flaggedCount>0&&<span className=\"badge badge-flagged\">{flaggedCount} flagged</span>}\n                  <select style={{width:140,marginLeft:'auto'}} value={filterStatus} onChange={e=>setFilterStatus(e.target.value)}>\n                    <option value=\"\">All</option>\n                    <option value=\"pending\">Pending</option>\n                    <option value=\"approved\">Approved</option>\n                    <option value=\"flagged\">Flagged</option>\n                  </select>\n                </div>\n\n                {/* Live pricing controls */}\n                <div className=\"card\" style={{marginBottom:14,background:'var(--blue-bg)',border:'1px solid var(--blue-border)'}}>\n                  <div style={{fontSize:12,fontWeight:600,color:'var(--blue)',marginBottom:10}}>\n                    LIVE PRICING — adjust and watch all prices update instantly\n                  </div>\n                  <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:10}}>\n                    <div>\n                      <label style={{fontSize:11,color:'var(--text-2)',display:'block',marginBottom:4}}>Tax (%)</label>\n                      <input type=\"number\" step=\"0.5\" value={settings.tax}\n                        onChange={e=>setSettings(s=>({...s,tax:Number(e.target.value)}))}\n                        style={{width:'100%',padding:'7px 10px',border:'1px solid var(--blue-border)',borderRadius:6,background:'var(--surface)',fontSize:14}}/>\n                    </div>\n                    <div>\n                      <label style={{fontSize:11,color:'var(--text-2)',display:'block',marginBottom:4}}>Markup (×)</label>\n                      <input type=\"number\" step=\"0.1\" value={settings.markup}\n                        onChange={e=>setSettings(s=>({...s,markup:Number(e.target.value)}))}\n                        style={{width:'100%',padding:'7px 10px',border:'1px solid var(--blue-border)',borderRadius:6,background:'var(--surface)',fontSize:14}}/>\n                    </div>\n                    <div>\n                      <label style={{fontSize:11,color:'var(--text-2)',display:'block',marginBottom:4}}>Shipping ($/kg)</label>\n                      <input type=\"number\" step=\"0.1\" value={settings.shipping}\n                        onChange={e=>setSettings(s=>({...s,shipping:Number(e.target.value)}))}\n                        style={{width:'100%',padding:'7px 10px',border:'1px solid var(--blue-border)',borderRadius:6,background:'var(--surface)',fontSize:14}}/>\n                    </div>\n                  </div>\n                  <div style={{display:'flex',gap:8,marginTop:10}}>\n                    <button className=\"btn btn-sm btn-primary\" onClick={saveSettings} disabled={savingSettings}>\n                      {savingSettings?'Saving...':'Save as default'}\n                    </button>\n                    <span style={{fontSize:11,color:'var(--blue)',alignSelf:'center'}}>\n                      Changes apply live to the preview below\n                    </span>\n                  </div>\n                </div>\n\n                {filteredItems.length===0?(\n                  <div className=\"empty\"><div className=\"empty-text\">No items match</div></div>\n                ):(\n                  <>\n                    {/* Approve all button */}\n                    {pendingCount>0&&(\n                      <div style={{display:'flex',justifyContent:'flex-end',marginBottom:8}}>\n                        <button className=\"btn btn-sm btn-success\" onClick={()=>{\n                          filteredItems.filter(i=>i.status==='pending').forEach(i=>updateItemStatus(i,'approved'));\n                        }}>✓ Approve all pending</button>\n                      </div>\n                    )}\n\n                    {/* Items cards */}\n                    {filteredItems.map(item=>{\n                      const retail = calcRetailPrice(item.price, item.category, settings);\n                      const cost   = calcUnitCost(item.price, item.category, settings);\n                      const variants = item.colors.length * item.sizes.length;\n                      return (\n                        <div key={item.id} className=\"item-card\" style={{\n                          borderLeft:`3px solid ${item.status==='approved'?'var(--green)':item.status==='flagged'?'var(--red)':'var(--amber-border)'}`\n                        }}>\n                          <div style={{display:'flex',alignItems:'flex-start',gap:10}}>\n                            <div style={{flex:1,minWidth:0}}>\n                              <div style={{fontWeight:600}}>{item.vendor} · <span style={{fontFamily:'monospace',fontSize:13}}>{item.code}</span></div>\n                              <div style={{fontSize:12,color:'var(--text-2)',marginTop:2}}>\n                                {item.category} · {item.colors.join(', ')} · {item.sizes.join('/')}\n                              </div>\n                              <div style={{fontSize:12,color:'var(--text-2)'}}>\n                                Purchase: ${item.price}/unit · Qty: {item.qty} units\n                              </div>\n                              {item.notes&&<div style={{fontSize:11,color:'var(--text-2)'}}>Note: {item.notes}</div>}\n                              {item.ownerNote&&<div style={{fontSize:11,color:'var(--amber)'}}>Your note: {item.ownerNote}</div>}\n                              {/* Live price preview */}\n                              <div style={{marginTop:6,padding:'6px 10px',background:'var(--bg)',borderRadius:6,\n                                display:'flex',gap:16,flexWrap:'wrap',fontSize:12}}>\n                                <span>Unit cost: <strong>${cost.toFixed(2)}</strong></span>\n                                <span>Retail price: <strong style={{color:'var(--green)',fontSize:13}}>${retail.toFixed(2)}</strong></span>\n                                <span style={{color:'var(--text-4)'}}>{variants} variant{variants!==1?'s':''} in Square</span>\n                              </div>\n                            </div>\n                            <div style={{display:'flex',gap:6,flexShrink:0,alignItems:'center',flexDirection:'column'}}>\n                              <span className={`badge badge-${item.status}`}>{item.status}</span>\n                              <div style={{display:'flex',gap:4}}>\n                                <button className=\"btn btn-sm btn-success\" onClick={()=>updateItemStatus(item,'approved')} title=\"Approve\">✓</button>\n                                <button className=\"btn btn-sm\" style={{borderColor:'var(--red-border)',color:'var(--red)'}}\n                                  onClick={()=>{setFlagModal({item});setFlagNote('');}} title=\"Flag\">⚑</button>\n                                <button className=\"btn btn-sm\" onClick={()=>{\n                                  setEditModal({item});\n                                  setEditPrice(String(item.price));\n                                  setEditNotes(item.notes);\n                                  setEditOwnerNote(item.ownerNote);\n                                }} title=\"Edit\">✎</button>\n                                <button className=\"btn btn-sm btn-ghost\" onClick={()=>deleteItem(item.id)}>✕</button>\n                              </div>\n                            </div>\n                          </div>\n                        </div>\n                      );\n                    })}\n\n                    {/* Square preview table */}\n                    <div style={{marginTop:20,marginBottom:14}}>\n                      <div style={{fontWeight:600,fontSize:14,marginBottom:10}}>\n                        Square CSV preview — {exportableRows} rows\n                      </div>\n                      <div style={{overflowX:'auto',borderRadius:'var(--radius)',border:'1px solid var(--border)'}}>\n                        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12,background:'var(--surface)'}}>\n                          <thead>\n                            <tr style={{background:'var(--bg)'}}>\n                              {['Item Name','Variation','SKU','Category','Price','Unit Cost','Color','Size','Vendor','Qty'].map(h=>(\n                                <th key={h} style={{padding:'8px 10px',textAlign:'left',fontWeight:600,\n                                  borderBottom:'1px solid var(--border)',whiteSpace:'nowrap',\n                                  color:'var(--text-2)',fontSize:11}}>{h}</th>\n                              ))}\n                            </tr>\n                          </thead>\n                          <tbody>\n                            {filteredItems.filter(i=>i.status!=='flagged').flatMap(item=>{\n                              const retail = calcRetailPrice(item.price, item.category, settings);\n                              const cost   = calcUnitCost(item.price, item.category, settings);\n                              const words  = item.vendor.trim().split(/\\s+/);\n                              const abbr   = words.length===1 ? item.vendor.substring(0,2).toUpperCase() : words.map((w:string)=>w[0]).join('').toUpperCase();\n                              const itemName = `${abbr}-${item.code} ${item.category}`;\n                              const colorCounts: Record<string,number> = {};\n                              const sizeCounts:  Record<string,number> = {};\n                              item.colors.forEach((c:string)=>{ colorCounts[c]=(colorCounts[c]||0)+1; });\n                              item.sizes.forEach((s:string)=>{ sizeCounts[s]=(sizeCounts[s]||0)+1; });\n                              const uColors = item.colors.filter((c:string,i:number)=>item.colors.indexOf(c)===i);\n                              const uSizes  = item.sizes.filter((s:string,i:number)=>item.sizes.indexOf(s)===i);\n                              return uColors.flatMap((color:string,ci:number)=>\n                                uSizes.map((size:string,si:number)=>{\n                                  const colorSlug=color.substring(0,3).toUpperCase().replace(/\\s/g,'');\n                                  const sizeSlug=String(size).toUpperCase().replace(/\\s/g,'');\n                                  const sku=`${abbr}-${item.code}-${colorSlug}-${sizeSlug}`;\n                                  const variantQty=(colorCounts[color]||1)*(sizeCounts[size]||1);\n                                  return (\n                                    <tr key={`${item.id}-${ci}-${si}`}\n                                      style={{borderBottom:'1px solid var(--border)'}}>\n                                      <td style={{padding:'6px 10px',fontWeight:500}}>{itemName}</td>\n                                      <td style={{padding:'6px 10px'}}>{color}, {size}</td>\n                                      <td style={{padding:'6px 10px',fontFamily:'monospace',fontSize:11}}>{sku}</td>\n                                      <td style={{padding:'6px 10px'}}>{item.category}</td>\n                                      <td style={{padding:'6px 10px',color:'var(--green)',fontWeight:600}}>${retail.toFixed(2)}</td>\n                                      <td style={{padding:'6px 10px'}}>${cost.toFixed(2)}</td>\n                                      <td style={{padding:'6px 10px'}}>{color}</td>\n                                      <td style={{padding:'6px 10px'}}>{size}</td>\n                                      <td style={{padding:'6px 10px'}}>{item.vendor}</td>\n                                      <td style={{padding:'6px 10px',fontWeight:600}}>{variantQty}</td>\n                                    </tr>\n                                  );\n                                })\n                              );\n                            })}\n                          </tbody>\n                        </table>\n                      </div>\n                    </div>\n                  </>\n                )}\n\n                {/* Export bar */}\n                <div style={{padding:14,background:'var(--surface)',border:'1px solid var(--border)',\n                  borderRadius:'var(--r-lg)',display:'flex',alignItems:'center',\n                  justifyContent:'space-between',gap:12,flexWrap:'wrap'}}>\n                  <div>\n                    <div style={{fontWeight:600}}>Export to Square</div>\n                    <div style={{fontSize:12,color:'var(--text-2)',marginTop:2}}>\n                      {exportableRows} rows · Tax: {settings.tax}% · Markup: {settings.markup}× · Shipping: ${settings.shipping}/kg\n                    </div>\n                  </div>\n                  <div style={{display:'flex',gap:8}}>\n                    <button className=\"btn btn-success\" style={{padding:'10px 20px'}}\n                      onClick={doExport} disabled={exporting||exportableRows===0}>\n                      {exporting?'Generating...':'⬇ Download CSV'}\n                    </button>\n                    <button className=\"btn btn-sm\" style={{borderColor:'var(--green-border)',color:'var(--green)'}}\n                      onClick={()=>closeOrder(selectedOrder.id)}>\n                      Mark imported\n                    </button>\n                  </div>\n                </div>\n              </>\n            )}\n          </>\n        )}\n\n        {/* ── WORKERS TAB ── */}\n        {tab==='workers'&&(\n          <>\n            <div className=\"card\" style={{marginBottom:14}}>\n              <div className=\"card-title\">Add worker</div>\n              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr auto',gap:10,alignItems:'end'}}>\n                <div>\n                  <label className=\"label\">Name</label>\n                  <input type=\"text\" placeholder=\"Worker name\" value={newWorkerName} onChange={e=>setNewWorkerName(e.target.value)}/>\n                </div>\n                <div>\n                  <label className=\"label\">PIN</label>\n                  <input type=\"text\" inputMode=\"numeric\" placeholder=\"4-digit PIN\" value={newWorkerPin} onChange={e=>setNewWorkerPin(e.target.value)}/>\n                </div>\n                <button className=\"btn btn-primary\" onClick={addWorker}>Add</button>\n              </div>\n            </div>\n            <div className=\"card\">\n              <div className=\"card-title\">Workers ({workers.length})</div>\n              {workers.length===0?(\n                <div className=\"empty\"><div className=\"empty-text\">No workers yet</div></div>\n              ):(\n                workers.map(w=>(\n                  <div key={w.id} className=\"vendor-row\">\n                    <div>\n                      <strong>{w.name}</strong>\n                      <span style={{marginLeft:10,fontFamily:'monospace',fontSize:12,color:'var(--text-2)'}}>PIN: {w.pin}</span>\n                    </div>\n                    <button className=\"btn btn-sm\" style={{color:'var(--red)',borderColor:'var(--red-border)'}}\n                      onClick={()=>removeWorker(w.id)}>Remove</button>\n                  </div>\n                ))\n              )}\n            </div>\n          </>\n        )}\n\n        {/* ── SETTINGS TAB ── */}\n        {tab==='settings'&&(\n          <div className=\"card\">\n            <div className=\"card-title\">Pricing defaults</div>\n            <div className=\"settings-grid\">\n              <div className=\"field\">\n                <label className=\"label\">Tax (%)</label>\n                <input type=\"number\" step=\"0.5\" value={settings.tax}\n                  onChange={e=>setSettings(s=>({...s,tax:Number(e.target.value)}))}/>\n              </div>\n              <div className=\"field\">\n                <label className=\"label\">Markup (×)</label>\n                <input type=\"number\" step=\"0.1\" value={settings.markup}\n                  onChange={e=>setSettings(s=>({...s,markup:Number(e.target.value)}))}/>\n              </div>\n              <div className=\"field\">\n                <label className=\"label\">Shipping ($/kg)</label>\n                <input type=\"number\" step=\"0.01\" value={settings.shipping}\n                  onChange={e=>setSettings(s=>({...s,shipping:Number(e.target.value)}))}/>\n              </div>\n            </div>\n            <div className=\"divider\"/>\n            <div className=\"field\" style={{maxWidth:200}}>\n              <label className=\"label\">Owner PIN</label>\n              <input type=\"text\" inputMode=\"numeric\" value={settings.ownerPin}\n                onChange={e=>setSettings(s=>({...s,ownerPin:e.target.value}))}/>\n            </div>\n            <button className=\"btn btn-primary\" onClick={saveSettings} disabled={savingSettings}>\n              {savingSettings?'Saving...':'Save settings'}\n            </button>\n          </div>\n        )}\n      </div>\n\n      {/* Edit modal */}\n      {editModal&&(\n        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.4)',display:'flex',\n          alignItems:'center',justifyContent:'center',padding:'1rem',zIndex:200}}>\n          <div className=\"card\" style={{width:'100%',maxWidth:480}}>\n            <div style={{fontWeight:600,marginBottom:4,fontSize:16}}>Edit item</div>\n            <div style={{fontSize:13,color:'var(--text-2)',marginBottom:16}}>\n              {editModal.item.vendor} · {editModal.item.code} · {editModal.item.category}\n            </div>\n\n            <div style={{background:'var(--bg)',borderRadius:8,padding:'10px 12px',marginBottom:14,fontSize:12,color:'var(--text-2)'}}>\n              <strong>Colors:</strong> {editModal.item.colors.join(', ')}<br/>\n              <strong>Sizes:</strong> {editModal.item.sizes.join(', ')}<br/>\n              <strong>Qty:</strong> {editModal.item.qty} units\n            </div>\n\n            <div className=\"field\">\n              <label className=\"label\">Purchase price (USD)</label>\n              <input type=\"number\" step=\"0.5\" value={editPrice}\n                onChange={e=>setEditPrice(e.target.value)}\n                style={{fontSize:16}}/>\n              {editPrice&&(\n                <div style={{fontSize:12,color:'var(--green)',marginTop:4}}>\n                  → Retail: <strong>${(Math.floor(((Number(editPrice)*(1+settings.tax/100))+(0.5*settings.shipping))*settings.markup)+0.99).toFixed(2)}</strong>\n                </div>\n              )}\n            </div>\n            <div className=\"field\">\n              <label className=\"label\">Worker note</label>\n              <input type=\"text\" value={editNotes} onChange={e=>setEditNotes(e.target.value)} placeholder=\"Worker note\"/>\n            </div>\n            <div className=\"field\" style={{marginBottom:16}}>\n              <label className=\"label\">Owner note (visible to worker)</label>\n              <input type=\"text\" value={editOwnerNote} onChange={e=>setEditOwnerNote(e.target.value)} placeholder=\"Note for worker...\"/>\n            </div>\n            <div style={{display:'flex',gap:8}}>\n              <button className=\"btn\" style={{flex:1}} onClick={()=>setEditModal(null)}>Cancel</button>\n              <button className=\"btn btn-primary\" style={{flex:1}} onClick={saveEditItem}>Save changes</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Flag modal */}\n      {flagModal&&(\n        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.4)',display:'flex',\n          alignItems:'center',justifyContent:'center',padding:'1rem',zIndex:200}}>\n          <div className=\"card\" style={{width:'100%',maxWidth:380}}>\n            <div style={{fontWeight:600,marginBottom:10}}>Flag item</div>\n            <div style={{fontSize:13,color:'var(--text-2)',marginBottom:12}}>\n              {flagModal.item.vendor} · {flagModal.item.code}\n            </div>\n            <div className=\"field\">\n              <label className=\"label\">Note for worker</label>\n              <input type=\"text\" placeholder=\"e.g. Wrong price, check colors\"\n                value={flagNote} onChange={e=>setFlagNote(e.target.value)} autoFocus/>\n            </div>\n            <div style={{display:'flex',gap:8}}>\n              <button className=\"btn\" style={{flex:1}} onClick={()=>setFlagModal(null)}>Cancel</button>\n              <button className=\"btn btn-danger\" style={{flex:1}} onClick={()=>{\n                updateItemStatus(flagModal.item,'flagged',flagNote||'Please review');\n                setFlagModal(null);\n              }}>Flag item</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {toast&&<div className=\"toast-wrap\"><div className=\"toast\">{toast}</div></div>}\n    </div>\n  );\n}\n", "src/app/api/notifications/route.ts": "// src/app/api/notifications/route.ts\nimport { NextRequest, NextResponse } from 'next/server';\nimport { getSettings } from '@/lib/sheets';\nimport { google } from 'googleapis';\n\nconst SHEET_ID = process.env.GOOGLE_SHEET_ID!;\nconst TAB = 'Notifications';\n\nfunction getAuth() {\n  return new google.auth.GoogleAuth({\n    credentials: {\n      client_email: process.env.GOOGLE_SERVICE_ACCOUNT_EMAIL,\n      private_key: process.env.GOOGLE_PRIVATE_KEY?.replace(/\\\\n/g, '\\n'),\n    },\n    scopes: ['https://www.googleapis.com/auth/spreadsheets'],\n  });\n}\nasync function getSheets() {\n  return google.sheets({ version: 'v4', auth: getAuth() });\n}\n\nexport interface Notification {\n  id: string;\n  type: 'order_started' | 'order_submitted' | 'item_flagged';\n  for: 'owner' | 'worker';\n  workerId?: string;\n  workerName?: string;\n  orderId?: string;\n  orderName?: string;\n  itemId?: string;\n  itemCode?: string;\n  message: string;\n  read: boolean;\n  createdAt: string;\n}\n\nasync function ensureTab() {\n  const sheets = await getSheets();\n  const meta = await sheets.spreadsheets.get({ spreadsheetId: SHEET_ID });\n  const exists = meta.data.sheets?.some(s => s.properties?.title === TAB);\n  if (!exists) {\n    await sheets.spreadsheets.batchUpdate({\n      spreadsheetId: SHEET_ID,\n      requestBody: { requests: [{ addSheet: { properties: { title: TAB } } }] },\n    });\n    await sheets.spreadsheets.values.update({\n      spreadsheetId: SHEET_ID,\n      range: `${TAB}!A1:J1`,\n      valueInputOption: 'RAW',\n      requestBody: { values: [['id','type','for','workerId','workerName','orderId','orderName','itemId','itemCode','message','read','createdAt']] },\n    });\n  }\n}\n\nexport async function GET(req: NextRequest) {\n  try {\n    await ensureTab();\n    const sheets = await getSheets();\n    const forWho = req.nextUrl.searchParams.get('for');\n    const workerId = req.nextUrl.searchParams.get('workerId');\n    const res = await sheets.spreadsheets.values.get({\n      spreadsheetId: SHEET_ID, range: `${TAB}!A2:L`,\n    });\n    let rows = (res.data.values ?? []).filter(r => r[0]);\n    if (forWho === 'owner') rows = rows.filter(r => r[2] === 'owner');\n    if (forWho === 'worker' && workerId) rows = rows.filter(r => r[2] === 'worker' && r[3] === workerId);\n    const notifications: Notification[] = rows.map(r => ({\n      id: r[0], type: r[1] as Notification['type'], for: r[2] as 'owner'|'worker',\n      workerId: r[3], workerName: r[4], orderId: r[5], orderName: r[6],\n      itemId: r[7], itemCode: r[8], message: r[9],\n      read: r[10] === 'true', createdAt: r[11],\n    }));\n    const unread = notifications.filter(n => !n.read).length;\n    return NextResponse.json({ notifications: notifications.reverse(), unread });\n  } catch (e: any) {\n    return NextResponse.json({ error: e.message }, { status: 500 });\n  }\n}\n\nexport async function POST(req: NextRequest) {\n  try {\n    await ensureTab();\n    const body = await req.json();\n    const sheets = await getSheets();\n\n    if (body.action === 'create') {\n      const n: Notification = {\n        id: 'n_' + Date.now(),\n        type: body.type,\n        for: body.for,\n        workerId: body.workerId || '',\n        workerName: body.workerName || '',\n        orderId: body.orderId || '',\n        orderName: body.orderName || '',\n        itemId: body.itemId || '',\n        itemCode: body.itemCode || '',\n        message: body.message,\n        read: false,\n        createdAt: new Date().toISOString(),\n      };\n      await sheets.spreadsheets.values.append({\n        spreadsheetId: SHEET_ID, range: `${TAB}!A:L`,\n        valueInputOption: 'RAW',\n        requestBody: { values: [[n.id,n.type,n.for,n.workerId,n.workerName,n.orderId,n.orderName,n.itemId,n.itemCode,n.message,String(n.read),n.createdAt]] },\n      });\n      return NextResponse.json({ ok: true, notification: n });\n    }\n\n    if (body.action === 'mark-read') {\n      // Find and update all unread for this recipient\n      const res = await sheets.spreadsheets.values.get({\n        spreadsheetId: SHEET_ID, range: `${TAB}!A:L`,\n      });\n      const rows = res.data.values ?? [];\n      const updates: any[] = [];\n      rows.forEach((row, i) => {\n        if (i === 0) return;\n        const matchOwner = body.for === 'owner' && row[2] === 'owner';\n        const matchWorker = body.for === 'worker' && row[2] === 'worker' && row[3] === body.workerId;\n        if ((matchOwner || matchWorker) && row[10] !== 'true') {\n          updates.push({ range: `${TAB}!K${i+1}`, values: [['true']] });\n        }\n      });\n      if (updates.length > 0) {\n        await sheets.spreadsheets.values.batchUpdate({\n          spreadsheetId: SHEET_ID,\n          requestBody: { valueInputOption: 'RAW', data: updates },\n        });\n      }\n      return NextResponse.json({ ok: true });\n    }\n    return NextResponse.json({ error: 'Unknown action' }, { status: 400 });\n  } catch (e: any) {\n    return NextResponse.json({ error: e.message }, { status: 500 });\n  }\n}\n", "src/app/api/orders/route.ts": "import { NextRequest, NextResponse } from 'next/server';\nimport { getAllOrders, getOrdersByWorker, createOrder, updateOrder } from '@/lib/sheets';\nimport type { Order } from '@/lib/types';\n\nexport async function GET(req: NextRequest) {\n  try {\n    const workerId = req.nextUrl.searchParams.get('workerId');\n    const orders = workerId ? await getOrdersByWorker(workerId) : await getAllOrders();\n    return NextResponse.json({ orders });\n  } catch (e: any) {\n    return NextResponse.json({ error: e.message }, { status: 500 });\n  }\n}\n\nexport async function POST(req: NextRequest) {\n  try {\n    const body = await req.json();\n    if (body.action === 'create') {\n      const order: Order = {\n        id: crypto.randomUUID(),\n        name: body.name,\n        startDate: body.startDate,\n        workerId: body.workerId,\n        workerName: body.workerName,\n        status: 'open',\n        shippingCost: 0,\n        workerCommission: 0,\n        totalOrderCost: 0,\n        createdAt: new Date().toISOString(),\n        closedAt: '',\n        itemCount: 0,\n        totalValue: 0,\n      };\n      await createOrder(order);\n      // Notify owner: order started\n      await fetch(new URL('/api/notifications', req.url), {\n        method: 'POST', headers: {'Content-Type':'application/json'},\n        body: JSON.stringify({\n          action: 'create', type: 'order_started', for: 'owner',\n          workerId: order.workerId, workerName: order.workerName,\n          orderId: order.id, orderName: order.name,\n          message: `${order.workerName} started a new order: \"${order.name}\"`,\n        }),\n      }).catch(()=>{});\n      return NextResponse.json({ order }, { status: 201 });\n    }\n    if (body.action === 'update') {\n      await updateOrder(body.order);\n      // If status changed to submitted, notify owner\n      if (body.order?.status === 'submitted') {\n        await fetch(new URL('/api/notifications', req.url), {\n          method: 'POST', headers: {'Content-Type':'application/json'},\n          body: JSON.stringify({\n            action: 'create', type: 'order_submitted', for: 'owner',\n            workerId: body.order.workerId, workerName: body.order.workerName,\n            orderId: body.order.id, orderName: body.order.name,\n            message: `${body.order.workerName} submitted order \"${body.order.name}\" — ready for review`,\n          }),\n        }).catch(()=>{});\n      }\n      return NextResponse.json({ ok: true });\n    }\n    if (body.action === 'close') {\n      const orders = await getAllOrders();\n      const order = orders.find(o => o.id === body.orderId);\n      if (!order) return NextResponse.json({ error: 'Not found' }, { status: 404 });\n      order.status = 'imported';\n      order.closedAt = new Date().toISOString();\n      await updateOrder(order);\n      return NextResponse.json({ ok: true });\n    }\n    return NextResponse.json({ error: 'Unknown action' }, { status: 400 });\n  } catch (e: any) {\n    return NextResponse.json({ error: e.message }, { status: 500 });\n  }\n}\n", "src/app/api/items/route.ts": "import { NextRequest, NextResponse } from 'next/server';\nimport { getAllItems, getItemsByOrder, appendItem, updateItem, deleteItem } from '@/lib/sheets';\nimport type { OrderItem } from '@/lib/types';\n\nexport async function GET(req: NextRequest) {\n  try {\n    const orderId = req.nextUrl.searchParams.get('orderId');\n    const items = orderId ? await getItemsByOrder(orderId) : await getAllItems();\n    return NextResponse.json({ items });\n  } catch (e: any) {\n    return NextResponse.json({ error: e.message }, { status: 500 });\n  }\n}\n\nexport async function POST(req: NextRequest) {\n  try {\n    const body = await req.json();\n    const item: OrderItem = {\n      id: crypto.randomUUID(),\n      orderId: body.orderId,\n      workerId: body.workerId || '',\n      vendor: body.vendor,\n      code: body.code,\n      category: body.category,\n      colors: body.colors,\n      sizes: body.sizes,\n      price: Number(body.price),\n      qty: Number(body.qty) || 1,\n      notes: body.notes || '',\n      ownerNote: '',\n      status: 'pending',\n      createdAt: new Date().toISOString(),\n    };\n    await appendItem(item);\n    return NextResponse.json({ item }, { status: 201 });\n  } catch (e: any) {\n    return NextResponse.json({ error: e.message }, { status: 500 });\n  }\n}\n\nexport async function PATCH(req: NextRequest) {\n  try {\n    const item: OrderItem = await req.json();\n    await updateItem(item);\n    // If item was flagged, notify the worker\n    if (item.status === 'flagged' && item.workerId) {\n      await fetch(new URL('/api/notifications', req.url), {\n        method: 'POST', headers: {'Content-Type':'application/json'},\n        body: JSON.stringify({\n          action: 'create', type: 'item_flagged', for: 'worker',\n          workerId: item.workerId,\n          orderId: item.orderId, orderName: '',\n          itemId: item.id, itemCode: item.code,\n          message: `Item ${item.vendor} · ${item.code} was flagged${item.ownerNote ? ': ' + item.ownerNote : ' — please review'}`,\n        }),\n      }).catch(()=>{});\n    }\n    return NextResponse.json({ ok: true });\n  } catch (e: any) {\n    return NextResponse.json({ error: e.message }, { status: 500 });\n  }\n}\n\nexport async function DELETE(req: NextRequest) {\n  try {\n    const { id } = await req.json();\n    await deleteItem(id);\n    return NextResponse.json({ ok: true });\n  } catch (e: any) {\n    return NextResponse.json({ error: e.message }, { status: 500 });\n  }\n}\n", "src/lib/types.ts": "// src/lib/types.ts\n\nexport type ItemStatus = 'pending' | 'approved' | 'flagged';\nexport type OrderStatus = 'open' | 'submitted' | 'imported';\n\nexport interface Worker {\n  id: string;\n  name: string;\n  pin: string;\n}\n\nexport interface OrderItem {\n  id: string;\n  orderId: string;\n  workerId?: string;\n  vendor: string;\n  code: string;\n  category: string;\n  colors: string[];\n  sizes: string[];\n  price: number;\n  qty: number;\n  notes: string;\n  ownerNote: string;\n  status: ItemStatus;\n  createdAt: string;\n}\n\nexport interface Order {\n  id: string;\n  name: string;\n  startDate: string;\n  workerId: string;\n  workerName: string;\n  status: OrderStatus;\n  shippingCost: number;\n  workerCommission: number;  // 3% of totalValue (excluding shipping)\n  totalOrderCost: number;    // totalValue + shippingCost + workerCommission\n  createdAt: string;\n  closedAt: string;\n  itemCount: number;\n  totalValue: number;\n}\n\nexport interface SessionSettings {\n  tax: number;\n  markup: number;\n  shipping: number;\n  ownerPin: string;\n}\n"};

for (const [filePath, content] of Object.entries(files)) {
  const full = path.join(root, filePath);
  fs.mkdirSync(path.dirname(full), { recursive: true });
  fs.writeFileSync(full, content, 'utf8');
  console.log('Written:', filePath);
}
